import React from "react";
import { Container, Row, Col } from "react-bootstrap";

const Footer = () => {
  const currentyear = new Date().getFullYear();
  return (
    <>
      <Container>
        <Row>
          <Col className="text-center py-3">
            <p>Pandeystore & copy {currentyear}</p>
          </Col>
        </Row>
      </Container>
    </>
  );
};

export default Footer;
